import java.io.FileWriter;
import java.io.IOException;
import java.io.PrintWriter;
import org.owasp.esapi.ESAPI;

public class SecureCode {

    public static void main(String[] args) throws IOException {
        String userInput = "<script>alert('XSS vulnerability')</script>";

        // Properly encoding user input to prevent XSS attacks
        String encodedUserInput = ESAPI.encoder().encodeForHTML(userInput);

        // Writing the sanitized user input to an HTML file
        PrintWriter out = new PrintWriter(new FileWriter("output.html"));
        out.println("<html><body>");
        out.println("<h1>Welcome, " + encodedUserInput + "</h1>");
        out.println("</body></html>");
        out.close();

        System.out.println("HTML file generated successfully with sanitized user input.");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
